// Parse WTTJ alert email HTML and extract job listings
// Email format: quoted-printable encoded HTML where each job is wrapped in
// <a href="sendgrid-tracking-url"><table class="es-content-body">...</table></a>
// containing: company logo (alt text), company name (<strong>),
// job title (<strong>), salary and location (<em>)
const items = [];

for (const item of $input.all()) {
  const html = item.json.html || item.json.textHtml || item.json.body || '';
  const receivedDate = item.json.date || item.json.internalDate || new Date().toISOString();

  // Each job card is an <a> wrapping a <table class="es-content-body"> with <tbody class="greyHover">
  // Split on greyHover to isolate each job block
  const jobBlocks = html.split('greyHover');

  for (let i = 1; i < jobBlocks.length; i++) {
    const block = jobBlocks[i];

    // Extract company name from logo alt text: alt="CompanyName logo"
    // Handle both quoted-printable (=3D) and normal encoding
    const logoAltMatch = block.match(/alt=3D"([^"]+?)\s+logo"/i) ||
                         block.match(/alt="([^"]+?)\s+logo"/i);
    const company = logoAltMatch ? logoAltMatch[1].trim() : '';

    // Skip blocks that don't have a company (not a job block)
    if (!company) continue;

    // Extract the tracking URL from the <a> tag before this block
    // Look in the previous block for the href that ends right before es-content-body
    const prevBlock = jobBlocks[i - 1];
    // The href is in a long <a> tag right before the <table...es-content-body>
    // Find all href values and take the last one (closest to this block)
    const allHrefs = prevBlock.match(/href=3D"(https:[^"]+)"/g) ||
                     prevBlock.match(/href="(https:[^"]+)"/g) || [];
    let trackingUrl = '';
    if (allHrefs.length > 0) {
      const lastHref = allHrefs[allHrefs.length - 1];
      const urlMatch = lastHref.match(/"(https:[^"]+)"/) ||
                      lastHref.match(/=3D"(https:[^"]+)"/);
      if (urlMatch) {
        trackingUrl = urlMatch[1]
          .replace(/=3D/g, '=')
          .replace(/=\r?\n/g, '')
          .replace(/\r?\n/g, '');
      }
    }

    // Extract job title from <strong> tags in the job details section
    // The company name appears in one <strong>, the job title in another
    const strongRegex = /<strong>\s*([\s\S]*?)\s*<\/strong>/g;
    let jobTitle = '';
    let strongMatch;
    while ((strongMatch = strongRegex.exec(block)) !== null) {
      const text = strongMatch[1]
        .replace(/=3D/g, '=')
        .replace(/=\r?\n/g, '')
        .replace(/\r?\n/g, '')
        .replace(/<[^>]+>/g, '')
        .replace(/\s+/g, ' ')
        .trim();
      // Skip if empty or matches company name
      if (text && text !== company) {
        jobTitle = text;
        break;
      }
    }

    // Extract salary and location from <em> tag
    const emMatch = block.match(/<em[^>]*>([\s\S]*?)<\/em>/i);
    let location = '';
    let salary = '';
    if (emMatch) {
      const emContent = emMatch[1]
        .replace(/<br\s*\/?>/gi, '\n')
        .replace(/<[^>]+>/g, '')
        .replace(/=3D/g, '=')
        .replace(/=\r?\n/g, '')
        .replace(/\r?\n/g, ' ')
        .replace(/&nbsp;/g, ' ')
        .replace(/=20/g, ' ')
        .replace(/\s+/g, ' ');
      const lines = emContent.split('\n').map(l => l.trim()).filter(l => l);
      for (const line of lines) {
        if (line.match(/\$[\d,.]+/i) || line.match(/salary/i) || line.match(/\d+[kK]/)) {
          salary = line.trim();
        } else if (line.length > 1) {
          location = line.trim();
        }
      }
      // If we didn't split properly, try to parse the combined text
      if (!salary && !location) {
        const combined = emContent.trim();
        const salaryMatch = combined.match(/(Salary:\s*\$[\d,.\-kK]+)/i);
        if (salaryMatch) salary = salaryMatch[1];
        const locMatch = combined.replace(salaryMatch ? salaryMatch[0] : '', '').trim();
        if (locMatch) location = locMatch;
      }
    }

    items.push({
      json: {
        'Date Received': new Date(receivedDate).toISOString().split('T')[0],
        'Company': company,
        'Job Title': jobTitle,
        'URL': trackingUrl,
        'Location': location,
        'Salary': salary,
        'Status': 'New'
      }
    });
  }
}

// If no jobs found, return a diagnostic item
if (items.length === 0) {
  items.push({
    json: {
      'Date Received': new Date().toISOString().split('T')[0],
      'Company': '⚠ NO JOBS PARSED',
      'Job Title': 'Check email format — parsing may need updating',
      'URL': '',
      'Location': '',
      'Salary': '',
      'Status': 'Error'
    }
  });
}

return items;

// Extract the final WTTJ URL from the redirect Location header
// and merge it back with the parsed job data
const items = [];

for (let i = 0; i < $input.all().length; i++) {
  const httpItem = $input.all()[i];
  const parsedItem = $('Parse WTTJ Email').all()[i];

  let finalUrl = parsedItem.json['URL']; // fallback to tracking URL

  // Check for redirect Location header
  const headers = httpItem.json?.headers || httpItem.json?.responseHeaders || {};
  const location = headers['location'] || headers['Location'] || '';
  if (location && location.includes('welcometothejungle.com')) {
    // Clean the URL - take just the base URL without UTM params
    finalUrl = location.split('?')[0];
  }

  items.push({
    json: {
      'Date Received': parsedItem.json['Date Received'],
      'Company': parsedItem.json['Company'],
      'Job Title': parsedItem.json['Job Title'],
      'URL': finalUrl,
      'Location': parsedItem.json['Location'],
      'Salary': parsedItem.json['Salary'],
      'Status': 'New'
    }
  });
}

return items;
